  +		const parsed: Partial<Record<keyof Omit<TeacherPolicy, "name">, number>> = {};
  +		for (const field of POLICY_FIELDS) {
  +			const match = content.match(new RegExp(`${field}\\s*:\\s*(-?\\d+(?:\\.\\d+)?)`, "i"));
  +			if (match) {
